module RefModule(
    input clk,
    input reset,      
    output [3:0] q);reg [3:0] count;

    assign q = count;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            count <= 0;
        else
            count <= count + 1;
    end

endmodule
